// App.js - Main React Application
import React, { useState, useEffect } from 'react';
import { BrowserRouter as Router, Routes, Route } from 'react-router-dom';
import IndividualAnalysis from './components/IndividualAnalysis';
import BatchAnalysis from './components/BatchAnalysis';
import Header from './components/Header';
import Sidebar from './components/Sidebar';
import './App.css';

function App() {
  const [analysisMode, setAnalysisMode] = useState('individual');
  const [modelAvailable, setModelAvailable] = useState(false);

  useEffect(() => {
    // Simulate model loading
    const timer = setTimeout(() => {
      setModelAvailable(false); // Set to true if model files exist
    }, 1000);
    return () => clearTimeout(timer);
  }, []);

  return (
    <Router>
      <div className="app">
        <Header />

        <div className="app-container">
          <Sidebar 
            analysisMode={analysisMode}
            setAnalysisMode={setAnalysisMode}
            modelAvailable={modelAvailable}
          />

          <main className="main-content">
            {!modelAvailable && (
              <div className="demo-warning">
                <strong>Model Status:</strong> Using simulated predictions and feature importances for demo. 
                To enable real predictions: 1. Install required packages 2. Place model files in Artifacts folder.
              </div>
            )}

            <Routes>
              <Route 
                path="/" 
                element={
                  analysisMode === 'individual' ? 
                  <IndividualAnalysis /> : 
                  <BatchAnalysis />
                } 
              />
            </Routes>
          </main>
        </div>
      </div>
    </Router>
  );
}

export default App;
